public int compareTo(DurationField otherField) {
    if (!otherField.isSupported()) {
        return -1;
    }
    if (!isSupported()) {
        return 1;
    }
    long thisUnitMillis = getUnitMillis();
    long otherUnitMillis = otherField.getUnitMillis();
    if (thisUnitMillis < otherUnitMillis) {
        return -1;
    } else if (thisUnitMillis > otherUnitMillis) {
        return 1;
    } else {
        return 0;
    }
}
